import sys
import pytest
from source import gcd

def test_gcd_recursive_order_causes_infinite_recursion():
    sys.setrecursionlimit(100)
    try:
        result = gcd(35, 21)
    except RecursionError:
        pytest.fail(
            "gcd(35, 21) hit RecursionError — recursive call passes (a % b, b) "
            "instead of (b, a % b), so b never decreases and the base case is never reached"
        )
    assert result == 7, f"gcd(35, 21) should return 7, got {result}"
